"use client"

import * as React from "react"
import { AnimatePresence, motion, useReducedMotion } from "framer-motion"
import { ChevronLeft, ChevronRight } from "lucide-react"
import {
  CaptionLabel,
  DayContent,
  DayPicker,
  type CaptionLabelProps,
  type DayContentProps,
} from "react-day-picker"

import { cn } from "@/lib/utils"
import { buttonVariants } from "@/components/ui/button"

function Calendar({
  className,
  classNames,
  components,
  month,
  defaultMonth,
  onMonthChange,
  showOutsideDays = true,
  ...props
}: React.ComponentProps<typeof DayPicker>) {
  const shouldReduceMotion = useReducedMotion()
  const [visibleMonth, setVisibleMonth] = React.useState(
    () => month ?? defaultMonth ?? new Date()
  )

  React.useEffect(() => {
    if (month) {
      setVisibleMonth(month)
    }
  }, [month])

  const handleMonthChange = React.useCallback(
    (nextMonth: Date) => {
      if (!month) {
        setVisibleMonth(nextMonth)
      }

      onMonthChange?.(nextMonth)
    },
    [month, onMonthChange]
  )

  const transition = React.useMemo(
    () =>
      shouldReduceMotion
        ? { duration: 0 }
        : { type: "spring" as const, stiffness: 360, damping: 34, mass: 0.7 },
    [shouldReduceMotion]
  )
  const contentTransition = React.useMemo(
    () =>
      shouldReduceMotion
        ? { duration: 0 }
        : { type: "spring" as const, stiffness: 420, damping: 30, mass: 0.55 },
    [shouldReduceMotion]
  )

  const CaptionLabelComponent = components?.CaptionLabel ?? CaptionLabel
  const DayContentComponent = components?.DayContent ?? DayContent

  const AnimatedCaptionLabel = React.useCallback(
    (captionProps: CaptionLabelProps) => (
      <div className="relative inline-grid min-w-24 place-items-center overflow-hidden">
        <AnimatePresence mode="popLayout" initial={false}>
          <motion.span
            key={`${captionProps.displayMonth.getFullYear()}-${captionProps.displayMonth.getMonth()}`}
            initial={
              shouldReduceMotion
                ? false
                : { opacity: 0, y: 5, filter: "blur(5px)" }
            }
            animate={{ opacity: 1, y: 0, filter: "blur(0px)" }}
            exit={
              shouldReduceMotion
                ? { opacity: 0 }
                : { opacity: 0, y: -5, filter: "blur(5px)" }
            }
            transition={contentTransition}
            className="col-start-1 row-start-1 transform-gpu"
          >
            <CaptionLabelComponent {...captionProps} />
          </motion.span>
        </AnimatePresence>
      </div>
    ),
    [CaptionLabelComponent, contentTransition, shouldReduceMotion]
  )

  const AnimatedDayContent = React.useCallback(
    (dayContentProps: DayContentProps) => (
      <span className="relative inline-grid size-full place-items-center overflow-hidden">
        <AnimatePresence mode="popLayout" initial={false}>
          <motion.span
            key={dayContentProps.date.getTime()}
            initial={
              shouldReduceMotion
                ? false
                : { opacity: 0, y: 6, scale: 0.96, filter: "blur(5px)" }
            }
            animate={{ opacity: 1, y: 0, scale: 1, filter: "blur(0px)" }}
            exit={
              shouldReduceMotion
                ? { opacity: 0 }
                : { opacity: 0, y: -6, scale: 0.96, filter: "blur(5px)" }
            }
            transition={contentTransition}
            className="col-start-1 row-start-1 transform-gpu"
          >
            <DayContentComponent {...dayContentProps} />
          </motion.span>
        </AnimatePresence>
      </span>
    ),
    [DayContentComponent, contentTransition, shouldReduceMotion]
  )

  return (
    <motion.div
      layout
      transition={transition}
      className="origin-top overflow-hidden"
    >
      <DayPicker
        month={visibleMonth}
        defaultMonth={defaultMonth}
        onMonthChange={handleMonthChange}
        showOutsideDays={showOutsideDays}
        className={cn("p-3", className)}
        classNames={{
          months: "flex flex-col sm:flex-row gap-2",
          month: "flex flex-col gap-4",
          caption: "flex justify-center pt-1 relative items-center w-full",
          caption_label: "text-sm font-medium",
          nav: "flex items-center gap-1",
          nav_button: cn(
            buttonVariants({ variant: "outline" }),
            "size-7 bg-transparent p-0 opacity-50 hover:opacity-100"
          ),
          nav_button_previous: "absolute left-1",
          nav_button_next: "absolute right-1",
          table: "w-full border-collapse space-x-1",
          head_row: "flex",
          head_cell:
            "text-muted-foreground rounded-md w-8 font-normal text-[0.8rem]",
          row: "flex w-full mt-2",
          cell: cn(
            "relative p-0 text-center text-sm focus-within:relative focus-within:z-20 [&:has([aria-selected])]:bg-accent [&:has([aria-selected].day-range-end)]:rounded-r-md",
            props.mode === "range"
              ? "[&:has(>.day-range-end)]:rounded-r-md [&:has(>.day-range-start)]:rounded-l-md first:[&:has([aria-selected])]:rounded-l-md last:[&:has([aria-selected])]:rounded-r-md"
              : "[&:has([aria-selected])]:rounded-md"
          ),
          day: cn(
            buttonVariants({ variant: "ghost" }),
            "size-8 p-0 font-normal aria-selected:opacity-100"
          ),
          day_range_start:
            "day-range-start aria-selected:bg-primary aria-selected:text-primary-foreground",
          day_range_end:
            "day-range-end aria-selected:bg-primary aria-selected:text-primary-foreground",
          day_selected:
            "bg-primary text-primary-foreground hover:bg-primary hover:text-primary-foreground focus:bg-primary focus:text-primary-foreground",
          day_today: "bg-accent text-accent-foreground",
          day_outside:
            "day-outside text-muted-foreground opacity-35 aria-selected:text-muted-foreground",
          day_disabled: "text-muted-foreground opacity-50",
          day_range_middle:
            "aria-selected:bg-accent aria-selected:text-accent-foreground",
          day_hidden: "invisible",
          ...classNames,
        }}
        components={{
          ...components,
          CaptionLabel: AnimatedCaptionLabel,
          DayContent: AnimatedDayContent,
          IconLeft: ({ className, ...props }) => (
            <ChevronLeft className={cn("size-4", className)} {...props} />
          ),
          IconRight: ({ className, ...props }) => (
            <ChevronRight className={cn("size-4", className)} {...props} />
          ),
        }}
        {...props}
      />
    </motion.div>
  )
}

export { Calendar }

import * as React from "react"
import { Slot } from "@radix-ui/react-slot"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"

const buttonVariants = cva(
  "inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-md text-sm font-medium transition-all disabled:pointer-events-none disabled:opacity-50 [&_svg]:pointer-events-none [&_svg:not([class*='size-'])]:size-4 shrink-0 [&_svg]:shrink-0 outline-none focus-visible:border-ring focus-visible:ring-ring/50 focus-visible:ring-[3px] aria-invalid:ring-destructive/20 dark:aria-invalid:ring-destructive/40 aria-invalid:border-destructive",
  {
    variants: {
      variant: {
        default:
          "bg-primary text-primary-foreground shadow-xs hover:bg-primary/90",
        destructive:
          "bg-destructive text-white shadow-xs hover:bg-destructive/90 focus-visible:ring-destructive/20 dark:focus-visible:ring-destructive/40 dark:bg-destructive/60",
        outline:
          "border bg-background shadow-xs hover:bg-accent hover:text-accent-foreground dark:bg-input/30 dark:border-input dark:hover:bg-input/50",
        secondary:
          "bg-secondary text-secondary-foreground shadow-xs hover:bg-secondary/80",
        ghost:
          "hover:bg-accent hover:text-accent-foreground dark:hover:bg-accent/50",
        link: "text-primary underline-offset-4 hover:underline",
      },
      size: {
        default: "h-9 px-4 py-2 has-[>svg]:px-3",
        sm: "h-8 rounded-md gap-1.5 px-3 has-[>svg]:px-2.5",
        lg: "h-10 rounded-md px-6 has-[>svg]:px-4",
        icon: "size-9",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  }
)

function Button({
  className,
  variant,
  size,
  asChild = false,
  ...props
}: React.ComponentProps<"button"> &
  VariantProps<typeof buttonVariants> & {
    asChild?: boolean
  }) {
  const Comp = asChild ? Slot : "button"

  return (
    <Comp
      data-slot="button"
      className={cn(buttonVariants({ variant, size, className }))}
      {...props}
    />
  )
}

export { Button, buttonVariants }

